#include <stdio.h>

unsigned char reverse_byte(unsigned char b) {
    unsigned char result = 0;
    for (int i = 0; i < 8; i++) {
        result <<= 1;
        result |= (b & 1);
        b >>= 1;
    }
    return result;
}

unsigned int reverse_32(unsigned int val) {
    unsigned int result = 0;
    for (int i = 0; i < 32; i++) {
        result <<= 1;
        result |= (val & 1);
        val >>= 1;
    }
    return result;
}

int main(void) {
    {
        printf("%d\n", (int)(reverse_byte(0xA5)));
        printf("%d\n", (int)(reverse_byte(0x0F)));
        printf("%d\n", (int)(reverse_byte(0x80)));
        printf("%d\n", (int)(reverse_byte(0x01)));
    }
    {
        printf("%d\n", (int)(reverse_32(0x12345678)));
        printf("%d\n", (int)(reverse_32(0x00000000)));
        printf("%d\n", (int)(reverse_32(0xFFFFFFFF)));
        printf("%d\n", (int)(reverse_32(0x00000001)));
    }
    return 0;
}

